noteContentFormat:
{% set baseUrl = url|slice:0,-1 %}{% set albumUrls = selector:ol.music-grid li.music-grid-item a?href %}{% set albumLisHtml = selectorHtml:ol.music-grid li.music-grid-item %}- [{{meta:property:og:title}}]({{url}})
{% for liHtml in albumLisHtml %}{% set albumName = liHtml|remove_html:"img"|markdown|strip_md|trim %}- [{{albumName}}]({{baseUrl}}{{albumUrls[loop.index0]}})
{% endfor %}
